var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"……그래서.","JPN":"……つまり。","ENG":"...So.","TWN":"……所以呢？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그대로 병원에 실려가 몇 주간 입원해 있었다?","JPN":"そのまま病院に運ばれて、何週間も入院していたと？","ENG":"That's how you ended up in the hospital for several weeks?","TWN":"就這樣被送進醫院住了幾周？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 식으로 쳐다보지 마세요. 딱히 병원비 문제로 손 빌리지도 않았잖아요.","JPN":"そんな目で見ないでください。病院代は自腹で払ったんですから。","ENG":"Don't look at me like that. I didn't ask you for help in paying the hospital bills.","TWN":"不、不要那樣看著我。我又沒有因為醫藥費問題向你借錢……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"누가 돈 때문이래? 난 네가 보육원 때문에 범죄자가 된 줄 알고 잠도 못 잤다, 야.","JPN":"そういう問題か？　私は孤児院が原因で君が犯罪者になったのかと思って、夜も眠れなかったんだ。","ENG":"This isn't about money. I lost sleep thinking that you became a criminal because of the orphanage.","TWN":"這是錢的問題嗎？我以為你因為育幼院成了罪犯，連覺都睡不著！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아하하… 결과가 좋으면 됐죠.","JPN":"あはは……結果オーライってことでいいじゃないですか。","ENG":"Ah ha ha... All's well that ends well.","TWN":"哈哈哈……結果是好的就行了……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런데 원장님. 일은 어쩌고 지금 시간에 여기 계세요?","JPN":"ところで、園長。業務時間内にこんなところにいても大丈夫なんですか？","ENG":"By the way, what are you doing here at this hour? What about your job?","TWN":"不過，院長，工作怎麼辦？你怎麼在這個時間跑過來？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 잘리셨어요?","JPN":"もしかしてクビになったとか？","ENG":"Were you fired?","TWN":"難道是被解雇了？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"넌 뭔 말을 그렇게 하냐? 그런 게 아니라 오늘 중요한 미팅이 있어서 그래.","JPN":"そういう発想はやめてくれ。今日は大事なミーティングがあるんだ。","ENG":"What are you talking about? I just had an important meeting today.","TWN":"說話怎麼不動動腦子呢？我今天是有個重要的會議。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"실은 네가 입원한 사이에 보육원에 후원자가 생겼거든.","JPN":"実は君が入院している間、孤児院を後援してくれる人が現れたんだ。","ENG":"The orphanage actually got a sponsor while you were in the hospital.","TWN":"其實在你住院期間，育幼院有了資助者。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"후원자요? 이런 허름한 보육원이 뭐가 좋다고 그런 걸 한대요?","JPN":"後援？　こんなボロい孤児院を、いったいどんな物好きが？","ENG":"A sponsor? Why would they sponsor a raggedy orphanage like this?","TWN":"資助者？這個破育幼院有什麼好資助的？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"나도 몰라. 듣기로는 재벌 2세라는데 이미지 메이킹이라도 하려나 보지.","JPN":"私もよくは知らん。財閥2世だそうだが、イメージアップでもしたいんだろう。","ENG":"I don't know. I heard she was from a wealthy family. I guess she's trying to look generous or something.","TWN":"我也不知道。聽說是富二代，可能是想打造形象吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"마침 오셨네. 난 다과나 준비할 테니 네가 잘 안내해 드려라.","JPN":"ちょうどいらっしゃったぞ。私はお菓子を用意してくるから、案内は君に任せた。","ENG":"Ah, she's here. I'm going to prepare some snacks, so show her in.","TWN":"喔，人來了。我去準備點心，你好好招待客人吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 일 보세요.","JPN":"はい、いってらっしゃい。","ENG":"Will do.","TWN":"是，院長去忙吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"신기하네. 고비 좀 넘겼다고 어떻게 이렇게 일이 술술 풀리지?","JPN":"変だな。ここ最近、何もかも上手くいきすぎてる。","ENG":"Interesting. I just went through a rough patch, but I didn't expect things to work out this well afterward.","TWN":"真奇怪……好不容易熬過了難關，事情就變得這麼順利了？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"고생 끝에 낙이 찾아온다더니… 이제야 겨우 나한테도 볕 들 날이 찾아오는구나.","JPN":"苦労の先には幸運が待つっていうけど……ついに私にも光が差したんだ。","ENG":"Well, I guess it's a reward for all the suffering I went through... Finally, things are looking up.","TWN":"苦盡甘來……終於輪到我也迎來光明的日子了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 잠시만요~.","JPN":"はい、今行きます～。","ENG":"Yes, coming!","TWN":"等一下，來了～"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"먼 길 오느라 고생 많으셨습니다. 그러니까-","JPN":"遥々遠方からお越しいただきありがとうございます。えっと―","ENG":"Thank you for coming all the way he–","TWN":"大老遠地跑過來辛苦…"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"썩 안내하지 못할까, 어이-.","JPN":"はやく案内しろ、コラ。","ENG":"Lead the way. Arr.","TWN":"怎麼還不帶路？"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"허억… 허억…….","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시, 심장아… 내가 방금 뭘 본 거지?","JPN":"び、びっくりした……今の何？","ENG":"W-what...? Did I just see who I thought I saw?","TWN":"我，我的心臟……我剛才看到了什麼？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그래. 분명 잘못 본 걸 거야. 아무렴. 피곤한 나머지 헛것을 본 게 분명해.","JPN":"きっと見間違いだよね。うんうん、疲労で幻覚が見えたに決まってる。","ENG":"No, I must be wrong. Yeah. I'm just tired so I'm seeing things.","TWN":"對，一定是看錯了。沒錯。肯定是太累了，產生了幻覺。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나도 참. 헛것에 홀려 손님분께 민폐를 끼치다니. 이럼 안 돼, 유피.","JPN":"そうだよ、幻覚が見えたからって、お客様に失礼な態度をとっちゃダメじゃない、ユピ。","ENG":"Come on, Yuppie. Get it together. You can't be rude to a guest just because you're seeing things.","TWN":"我也真是，被幻覺嚇到，給客人添了麻煩。這樣可不行，悠菲。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"죄송합니다~. 제가 잠시 헛것을 보는 바람에.","JPN":"すみません、ちょっと幻覚が見えてしまいまして。","ENG":"I'm sorry! I was mistaken.","TWN":"對不起！我剛才好像看錯了。"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"괜찮습니다. 크레데레가 이세상 귀여움이 아니긴 하죠.","JPN":"大丈夫ですよ。クレデレのあまりの可愛さに、幻覚を疑うのも仕方ありません。","ENG":"It is all right. Credere's adorable face often distracts people.","TWN":"沒關係，因為克蕾妲莉可愛到簡直不像是這個世界的。"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DEBT_04","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};